script:
frappe.ui.form.on('Tour Booking', {
    refresh: function(frm) {
        if (!frm.is_new()) {
            frm.add_custom_button(__('Print Zahaa Invoice'), function() {
                window.open('/printview?doctype=Tour%20Booking&name=' + frm.doc.name + '&format=ZAHA-INVESTOR-V1&no_letterhead=1', '_blank');
            }, __("Print"));
        }
    },
    validate: function(frm) {
        // AUTO-GLUE PASSENGER NAME FROM MAIN DOC TO ALL ROWS
        if (frm.doc.customer_name) {
            frm.doc.flights.forEach(row => {
                if (!row.custom_passenger_name) {
                    row.custom_passenger_name = frm.doc.customer_name;
                }
                if (!row.custom_ticket_class) {
                    row.custom_ticket_class = 'Y';
                }
            });
            frm.refresh_field("flights");
        }
    }
});
